CREATE TABLE ANALYTICS.FACT_LAB_RESULT
(
 LAB_RESULT_KEY       number(38,0) NOT NULL COMMENT 'Surrogate key for lab result fact row',
 ENCOUNTER_KEY        number(38,0) COMMENT 'Encounter surrogate key reference value (no FK constraint)',
 PATIENT_KEY          number(38,0) NOT NULL COMMENT 'Link to patient dimension',
 PROVIDER_KEY         number(38,0) COMMENT 'Ordering provider',
 LAB_TEST_CODE        varchar(50) NOT NULL COMMENT 'Lab test code',
 ORDER_DATE_KEY       number(8,0) COMMENT 'Date key when lab was ordered',
 RESULT_DATE_KEY      number(8,0) COMMENT 'Date key when result was finalized',
 RESULT_VALUE_NUMERIC number(18,4) COMMENT 'Numeric result value when applicable',
 RESULT_VALUE_TEXT    varchar(255) COMMENT 'Text result, for example Positive or Negative',
