 ABNORMAL_FLAG        varchar(10) COMMENT 'Flag for high, low, or critical results',
 REFERENCE_RANGE      varchar(100) COMMENT 'Reference range for the result',
 CREATED_TIMESTAMP    timestamp NOT NULL,
 CREATED_BY_NAME      varchar(50) NOT NULL,
 UPDATED_TIMESTAMP    timestamp NOT NULL,
