 CONSTRAINT pk_FACT_LAB_RESULT PRIMARY KEY ( LAB_RESULT_KEY ),
 CONSTRAINT fk_FACT_LAB_RESULT_DIM_DATE FOREIGN KEY ( ORDER_DATE_KEY ) REFERENCES ANALYTICS.DIM_DATE ( DATE_KEY ),
